import WorkpageHeader from '~/components/WorkpageHeader.vue';
import projectListElement from '~/components/projectListElement.vue';
import MainHeader from '~/components/MainHeader.vue';
export default {
  components: {
    WorkpageHeader: WorkpageHeader,
    projectListElement: projectListElement,
    MainHeader: MainHeader
  },
  computed: {
    yearsToProjects: function yearsToProjects() {
      var years = [];
      var projectLinks = this.$page.contentfulProjectsGallery.projectLink;

      for (var i = 0; i < projectLinks.length; i++) {
        var item = projectLinks[i];
        var thisYear = item.dateCreated.substring(0, 4);

        if (years[thisYear] == null) {
          years[thisYear] = [item];
        } else {
          years[thisYear].push(item);
        }
      }

      return years;
    }
  }
};
